import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router, RouterModule } from '@angular/router';
import { AuthService } from '../services/auth.service'; 

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterModule],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss']
})
export class LoginComponent implements OnInit {
  loginForm!: FormGroup;
  selectedRole: 'patient' | 'doctor' | 'admin' = 'patient';
  showPassword = false;

  constructor(
    private fb: FormBuilder, 
    private router: Router,
    private authService: AuthService 
  ) {}

  // 🚨 تهيئة الفورم أول ما الصفحة تفتح
  ngOnInit(): void {
    this.initForm();
  }

  initForm(): void {
    this.loginForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      rememberMe: [false]
    });
  }

  // 🚨 التبديل بين الـ Tabs (Patient, Doctor, Admin) عند الضغط
  selectRole(role: 'patient' | 'doctor' | 'admin'): void {
    this.selectedRole = role;
  }

  // 🚨 إظهار وإخفاء الباسورد
  togglePasswordVisibility(): void {
    this.showPassword = !this.showPassword;
  }

  // دالة الإرسال والتوجيه المحلي التجريبي (Local Bypass) لغاية ربط الباك إند
  onSubmit(): void {
    if (this.loginForm.valid) {
      const enteredEmail = this.loginForm.value.email;
      const enteredPassword = this.loginForm.value.password;

      console.log('Testing local login for role:', this.selectedRole);

      // 1️⃣ لو المستخدم اختار يدخل كـ Admin
      if (this.selectedRole === 'admin') {
        if (enteredEmail === 'admin@medilab.com' && enteredPassword === 'admin1234') {
          console.log('Admin local login success!');
          this.authService.storeSession('fake-admin-token', 'admin'); // تخزين جلسة وهمية
          this.router.navigate(['/admin-panel/dashboard']); // التوجيه للمسار الصحيح
        } else {
          alert('بيانات الأدمن غير صحيحة! جربي admin@medilab.com وباسورد admin1234');
        }
      }

      // 2️⃣ لو المستخدم اختار يدخل كـ Doctor
      else if (this.selectedRole === 'doctor') {
        if (enteredEmail === 'doctor@medilab.com' && enteredPassword === 'doctor1234') {
          console.log('Doctor local login success!');
          this.authService.storeSession('fake-doctor-token', 'doctor'); // تخزين جلسة وهمية
          this.router.navigate(['/doctor-panel/appointments']); // التوجيه لمواعيد الدكتور
        } else {
          alert('بيانات الدكتور غير صحيحة! جربي doctor@medilab.com وباسورد doctor1234');
        }
      }

      // 3️⃣ لو المستخدم اختار يدخل كـ Patient (تم التعديل للتحقق من البيانات)
      else if (this.selectedRole === 'patient') {
        if (enteredEmail === 'patient@medilab.com' && enteredPassword === 'patient1234') {
          console.log('Patient local login success!');
          this.authService.storeSession('fake-patient-token', 'patient'); // تخزين جلسة وهمية
          this.router.navigate(['/patient-panel']); // التوجيه للوحة المريض
        } else {
          alert('بيانات المريض غير صحيحة! جربي patient@medilab.com وباسورد patient1234');
        }
      }

    } else {
      this.loginForm.markAllAsTouched();
    }
  }
}
